var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。`,ENG:`that you'll be with him, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called him to your office. He said he'd be here soon.`,TWN:`做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`THADDEUS_PRYDWEN_NULL_NULL`,text:{KOREA:`하하핫! 종신계약이라고?`,JPN:`はははっ！　終身契約だと？`,ENG:`Hah hah hah! A lifetime contract, huh?`,TWN:`哈哈哈！你說終身契約？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`THADDEUS_PRYDWEN_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`THADDEUS_PRYDWEN_NULL_NULL`,text:{KOREA:`도시 하나를 인질로 잡았던 사상범만큼 대범해. 하여간 사장님도 스릴을 즐기는 인생이군.`,JPN:`一つの都市を占拠しようとするテロリストみたいに大胆な発想じゃないか。まったく、君もよっぽどスリル好きなんだな。`,ENG:`You're as bold as that political offender who took hostage of an entire city. You must like the thrill as much as I do.`,TWN:`就像把城市當人質的思想犯一樣大膽啊。不管怎麼說，老闆也喜歡享受刺激的人生啊。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`THADDEUS_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`THADDEUS_PRYDWEN_NULL_NULL`,text:{KOREA:`하지만 사장님, 신사란 인간들은 자기 기분 내킬 대로 하지 않아서 신사 아니겠나.`,JPN:`しかし、紳士ってのは気ままに行動しないからこそ、紳士と呼ばれるんじゃないか。`,ENG:`But a gentleman is a gentleman because he doesn't do as he pleases.`,TWN:`但是老闆，所謂的紳士，就是不被自己的情緒牽著走，才叫紳士的不是嗎？`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`THADDEUS_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`THADDEUS_PRYDWEN_NULL_NULL`,text:{KOREA:`이미 알고 계시겠지만, 난 젊은 시절부터 지저분한 일을 전문으로 해 왔거든.`,JPN:`すでに知っていると思うが、俺は若い頃から汚れ仕事を専門にしてきた。`,ENG:`As you may know already, I've been doing other people's dirty work since I was young.`,TWN:`我想你說不定已經知道了，我從年輕時就專做些髒活，這樣一路走過來的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`THADDEUS_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`THADDEUS_PRYDWEN_NULL_NULL`,text:{KOREA:`그쪽 부류와는 아직도 이래저래 복잡하게 얽혀 있지.`,JPN:`あっちの世界にいまだにいろいろと絡まれているんだよ。`,ENG:`I still have complicated relationships with some unsavoury people.`,TWN:`和那邊的人還是有很多糾纏不清的複雜關係。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`THADDEUS_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`THADDEUS_PRYDWEN_NULL_NULL`,text:{KOREA:`설렁거리는 노인네라고 너무 가까이 두면, 사장님까지 진흙탕 싸움에 빠지는 수가 있어.`,JPN:`フラフラした年寄りだと思って近寄ると、君まで泥仕合に巻き込まれるかもしれないぞ。`,ENG:`I don't want you to keep me close and end up getting involved with their nasty fights.`,TWN:`如果你因為我是個弱不禁風老頭就想靠近我，那連老闆都會陷入混戰中的。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`THADDEUS_PRYDWEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`THADDEUS_PRYDWEN_NULL_NULL`,text:{KOREA:`자, 결정은 사장님께 달렸소.`,JPN:`さぁ、選択は君次第だ。`,ENG:`But it's your call.`,TWN:`來吧，這件事由老闆做決定。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`THADDEUS_PRYDWEN_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};